import React from 'react'
import { useTranslation } from 'react-i18next'
import { Button, DialogOverlay, DialogOverlayActions, DialogOverlayFooter } from '@fs/zion-ui'
import { useRoleIndicator } from '@fs/zion-role-indicator'
import { exitRole } from './roles'

export default function ExitAdminModeOverlay({ overlay, roleName }) {
  const [t] = useTranslation()
  const { setRole } = useRoleIndicator()
  return (
    <DialogOverlay title={t('roles.exit-role.heading', 'Exit {roleName} Role', { roleName })} {...overlay}>
      {t('roles.exit-role.confirmation', 'Are you sure you want to exit the {roleName} Role?', { roleName })}

      <DialogOverlayFooter>
        <DialogOverlayActions>
          <Button onClick={() => overlay.close()}>{t('common-ui:cancel.action', 'Cancel')}</Button>
          <Button
            onClick={() => {
              setRole({})
              exitRole()
              overlay.close()
            }}
            emphasis="medium"
          >
            {t('roles.exit-role', 'Exit Role')}
          </Button>
        </DialogOverlayActions>
      </DialogOverlayFooter>
    </DialogOverlay>
  )
}
